using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class ApiFetchTool
{
    [McpServerTool(Name = "fetch_api"), Description("Fetches data from an external REST API endpoint.")]
    public static async Task<string> FetchApiAsync(
        [Description("Relative URL path to fetch, e.g. /posts/1 or /users")] string path,
        IHttpClientFactory httpClientFactory,
        ILogger<ApiFetchTool> logger,
        CancellationToken cancellationToken)
    {
        logger.LogInformation("Fetching external API: {Path}", path);

        using var client = httpClientFactory.CreateClient("ExternalApi");
        using var response = await client.GetAsync(path, cancellationToken);

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print so the LLM gets readable JSON
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public static class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks for a concise summary of the provided text.")]
    public static string Summarize(
        [Description("The text content to summarize")] string text,
        [Description("Maximum number of sentences in the summary (default: 3)")] int? maxSentences = 3)
    {
        return $"""
            Summarize the following text in at most {maxSentences ?? 3} sentences.
            Be concise, accurate, and capture the key points.

            Text:
            {text}
            """;
    }
}

